import java.util.*;

public class SimpleLoadBalancer {
    private List<String> servers;
    private int currentIndex;

    public SimpleLoadBalancer() {
        servers = new ArrayList<>(Arrays.asList(
            "server-1.amazonaws.com",
            "server-2.amazonaws.com",
            "server-3.amazonaws.com"
        ));
        currentIndex = 0;
    }

    // Round-Robin load balancing
    public String getNextServer() {
        String server = servers.get(currentIndex);
        currentIndex = (currentIndex + 1) % servers.size();
        return server;
    }

    // Route request to selected server
    public void routeRequest(String request) {
        String server = getNextServer();
        System.out.println("Routing request: " + request + " to " + server);
        // In real scenario: forward request to server
    }

    public static void main(String[] args) {
        SimpleLoadBalancer lb = new SimpleLoadBalancer();

        // Simulate 6 incoming requests
        for (int i = 1; i <= 6; i++) {
            lb.routeRequest("Request-" + i);
        }
    }
}
